using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// ── 1. GetTypeInfo<T>() — strongly-typed metadata ──────────────────
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 38), personInfo);
Console.WriteLine($"Serialized: {json}");

Person? roundTripped = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Deserialized: {roundTripped}");

// ── 2. TryGetTypeInfo<T>() — check without throwing ────────────────
// Person is resolvable via the default resolver → expect true
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"\nTryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now use a source-gen context that only knows about Person.
// Querying for an unknown type (UnknownType) returns false — no exception.
var restricted = new JsonSerializerOptions { TypeInfoResolver = SmallContext.Default };

if (restricted.TryGetTypeInfo<UnknownType>(out JsonTypeInfo<UnknownType>? missing))
{
    Console.WriteLine($"Unexpectedly found: {missing!.Type.Name}");
}
else
{
    Console.WriteLine("\nTryGetTypeInfo<UnknownType> returned false — metadata not available.");
}

// ── Types ───────────────────────────────────────────────────────────
public record Person(string Name, int Age);

public class UnknownType { public int Value { get; set; } }

